function sanitizeAngles(stepArr, prev){
  const out = prev.slice();
  for(let i=0;i<8;i++){
    const v = stepArr[i];
    if (v===null || v===undefined || v==='') continue;
    out[i] = Math.max(0, Math.min(180, ~~v));
  }
  return out;
}

// Merge B into A (ms/deg arrays). Skip null/undefined/''
function mergeMs(base, override){
  const out = base.slice();
  for(let i=0;i<8;i++){
    const v = override[i];
    if (v===null || v===undefined || v==='') continue;
    out[i] = Math.max(0, Math.min(65535, ~~v));
  }
