// Map UI speed 0..255 → ms/deg (linear; tune as needed)
function uiToMsPerDeg(ui){
  const u = Math.max(0, Math.min(255, ~~ui));
  // 0 → MAX_MS_PER_DEG (slow), 255 → MIN_MS_PER_DEG (fast)
