  for(let i=0;i<8;i++){
    const v = arr[i];
    if (v===null || v===undefined || v==='') { ms[i] = 0; continue; }
    ms[i] = isUiScale ? uiToMsPerDeg(v) : Math.max(0, Math.min(65535, ~~v));
  }
  while (ms.length < 8) ms.push(0);
