    let gestureSpeedMs = null;
    if (Array.isArray(g.speedMs)) gestureSpeedMs = toMsArray(g.speedMs, false);
    else if (Array.isArray(g.speed)) gestureSpeedMs = toMsArray(g.speed, true);

