  if (!newSpeedMs) return;
  if (!arraysEqual(newSpeedMs, lastSpeedMs)){
    node.send({ payload: frameVms(newSpeedMs) });
    lastSpeedMs = newSpeedMs.slice();
    context.set('lastSpeedMs', lastSpeedMs);
  }
