function sanitizeAngles(stepArr, prev){
  const out = prev.slice();
  for (let i=0;i<8;i++){
    const v = stepArr[i];
    if (v===null || v===undefined || v==='') continue;
    out[i] = Math.max(0, Math.min(180, ~~v));
  }
