function estimateStepTime(currentAngles, targetAngles, effectiveSpeed){
  let maxMs = 0;
  for (let i=0;i<8;i++){
    const delta = Math.abs((targetAngles[i]|0) - (currentAngles[i]|0));
    const spd   = effectiveSpeed[i]|0;
    const per   = msPerDeg(spd);
    const t     = (spd===0) ? 0 : delta * per;
    if (t > maxMs) maxMs = t;
  }
