// Normalize gesture: Option-D schema + legacy
function resolveGesture(name){
  const g = gestures[name];
  if (!g) return null;

  if (Array.isArray(g)){
    const steps = g.map(a => ({ angles: Array.isArray(a)?a:[] }));
    return { name, steps, defaultMs: DEFAULT_STEP_MS, gestureSpeed: null };
  }

  if (typeof g === 'object'){
    const defaultMs = Number(g.stepMs)>0 ? Number(g.stepMs) : DEFAULT_STEP_MS;
    const gestureSpeed = Array.isArray(g.speed) ? g.speed.slice(0,8) : null;
    const rawSteps = Array.isArray(g.steps) ? g.steps : [];
    const steps = rawSteps.map(st => {
      if (Array.isArray(st)) return { angles: st };
      const angles = Array.isArray(st && st.angles) ? st.angles : [];
      const ms     = (st && st.ms !== undefined) ? Math.max(0, Number(st.ms)||0) : undefined; // allow 0 dwell explicitly
      const speed  = Array.isArray(st && st.speed) ? st.speed.slice(0,8) : undefined;
      return { angles, ms, speed };
    });
