// ====== STEP GATING: both dwell + motion must be satisfied ================
function stepGateCheck(){
  if (!plan) return;

  const now = Date.now();
  // Mark gates that have reached their deadlines
  if (!plan.dwellDone && now >= plan.dwellDue) plan.dwellDone = true;
  if (!plan.motionDone && now >= plan.motionDue) plan.motionDone = true; // fallback if no DONE received

  if (plan.dwellDone && plan.motionDone){
    waiting = false; context.set('waiting', waiting);
    plan.idx += 1; context.set('plan', plan);
    sendCurrentStep();
    return;
  }

  // Not ready yet: schedule the next gate deadline
  const nextTs = Math.min(
    plan.dwellDone ? Infinity : plan.dwellDue,
    plan.motionDone ? Infinity : plan.motionDue
  );
  if (isFinite(nextTs)) scheduleAt(nextTs);
}

// ---- Core: send current step, then wait on BOTH gates ---------------------
function sendCurrentStep(){
  if (!plan) return;

  if (plan.idx >= plan.steps.length){
    node.warn(`Gesture "${plan.name}" finished (${plan.steps.length} steps).`);
    plan = null; context.set('plan', null);
    waiting = false; context.set('waiting', false);
    return;
  }

  const st = plan.steps[plan.idx];

  // Calculate effective speed for THIS step (merge lastSpeed with override)
  let effectiveSpeed = lastSpeed.slice();
  if (st.speed) {
    effectiveSpeed = mergeSpeeds(effectiveSpeed, st.speed);
    sendIfSpeedChanged(effectiveSpeed);
  }

  // Snapshot BEFORE we change angles (needed for estimator)
  const prevAng = ang.slice();

  // Apply angles for this step (allow nulls)
  ang = sanitizeAngles(st.angles || [], ang);
  global.set('angle', ang);

  // Send A frame
  node.send({ payload: frameA(ang) });

  // Compute dwell + motion deadlines (both must complete)
  const dwellMs = (st.ms !== undefined ? st.ms : (plan.defaultMs || DEFAULT_STEP_MS));
  const motionEst = estimateStepTime(prevAng, ang, effectiveSpeed);

  plan.dwellDue  = Date.now() + dwellMs;
  plan.motionDue = Date.now() + motionEst;
  plan.dwellDone = (dwellMs === 0);      // 0 dwell means "no dwell gate"
  plan.motionDone = false;

  context.set('plan', plan);

  // schedule to the earlier of the two deadlines
  scheduleAt(Math.min(plan.dwellDue, plan.motionDue));

  waiting = true; context.set('waiting', waiting);
}

