const idleTimeoutMs    = Number(global.get('handIdleTimeoutMs')    ?? 700);  // if no message for this long -> ZERO
const zeroOnNoHand     = (global.get('zeroOnNoHand') !== false);             // default true
const noHandResendMs   = Number(global.get('noHandResendMs')       ?? 0);    // 0 = one-shot, >0 keep resending
const zeroPose         = Array.isArray(global.get('zeroPose')) ? global.get('zeroPose') : [0,0,0,0,0,90,40,0];

// ==== bicep config (defaults) ===============================================
const BICEP_MIN = Number(global.get('bicepMin') ?? 0);    // default lower bound
const BICEP_MAX = Number(global.get('bicepMax') ?? 50);   // default upper bound (0..50 as requested)

// elbow->norm mapping defaults (match python defaults if elbow_deg is provided)
const ELBOW_MIN_DEG = Number(global.get('elbowMinDeg') ?? 50);   // elbow angle considered fully flexed
const ELBOW_MAX_DEG = Number(global.get('elbowMaxDeg') ?? 170);  // elbow angle considered extended

// calibration for legacy 'virtual' input
const cal = global.get('inmoovCal') || { Fmax:60, open:[0,0,0,0,0], close:[160,160,160,160,160], rest:[90,90,90], mirrorIndexToThumb:false };

// ==== per-hand state & watchdog ============================================
function getState(hand){
  const key = "inmoov_state_"+hand;
  let st = context.get(key);
  if (!st) { st={ lastSent:[...zeroPose], live:[...zeroPose], lastTs:0, speedSent:false }; context.set(key, st); }
  return { key, st };
}
function armWatchdog(hand){
  // cancel any previous watchdog
  const k = "wd_"+hand; const prev = context.get(k);
  if (prev) { clearTimeout(prev); context.set(k,null); }
  if (!zeroOnNoHand || idleTimeoutMs<=0) return;
  const tid = setTimeout(function sendZero(){
    // send ZERO pose even if unchanged; optionally repeat
    const { key, st } = getState(hand);
    const a = zeroPose.slice(0,8);
    node.send({ payload: frameA(a), hand });  // force emit
    st.lastSent = a.slice(); st.live = a.slice(); st.lastTs = Date.now(); context.set(key, st);
    if (noHandResendMs>0) {
      const rep = setTimeout(sendZero, noHandResendMs);
      context.set(k, rep);
    }
  }, idleTimeoutMs);
  context.set(k, tid);
}

// ==== parse & normalize incoming ===========================================
const parsed = tryParsePayload(msg.payload);
if (!parsed) { return null; }

const payload = parsed;
const hand    = (typeof payload.hand === 'string') ? payload.hand : (typeof msg.hand === 'string' ? msg.hand : "Unknown");
const visible = !!payload.visible;   // Python should set visible=true/false

// Always (re)arm watchdog on any message we receive for this hand
armWatchdog(hand);

// If message says "not visible", zero immediately (and watchdog will keep it zero)
if (!visible && zeroOnNoHand) {
  const a = zeroPose.slice(0,8);
  const { key, st } = getState(hand);
  // push now even if unchanged
  node.send({ payload: frameA(a), hand });
  st.lastSent = a.slice(); st.live = a.slice(); st.lastTs = Date.now(); context.set(key, st);
  return null;
}

// ======== path A: direct 'angles' (preferred by hand_tendon_stream.py) =====
if (Array.isArray(payload.angles) && payload.angles.length >= 5) {
  const rest = Array.isArray(payload.rest) ? payload.rest.slice(0,3) : (Array.isArray(msg.restAngles)?msg.restAngles.slice(0,3):[90,90,90]);
  const next = [];
  for (let i=0;i<5;i++) next[i] = clamp(Math.round(Number(payload.angles[i]||0)),0,180);
  for (let i=0;i<3;i++) next[5+i] = clamp(Math.round(Number(rest[i]||90)),0,180);

  // ----- integrate bicep (payload.arm) into next[6] (7th slot) -----
  if (payload.arm && typeof payload.arm === 'object') {
    let bVal = null;
    if (typeof payload.arm.bicep_servo === 'number') {
      bVal = Math.round(payload.arm.bicep_servo);
    } else if (typeof payload.arm.norm === 'number') {
      const norm = clamp(Number(payload.arm.norm), 0, 1);
      bVal = Math.round(norm * (BICEP_MAX - BICEP_MIN) + BICEP_MIN);
    } else if (typeof payload.arm.elbow_deg === 'number') {
      const deg = Number(payload.arm.elbow_deg);
      const norm = clamp((ELBOW_MAX_DEG - deg) / Math.max(1e-6, (ELBOW_MAX_DEG - ELBOW_MIN_DEG)), 0, 1);
      bVal = Math.round(norm * (BICEP_MAX - BICEP_MIN) + BICEP_MIN);
    }
    if (bVal !== null && !Number.isNaN(bVal)) {
      next[6] = clamp(Math.round(bVal), BICEP_MIN, BICEP_MAX);
    } else {
      // ensure slot exists and keep rest-provided value (already assigned above)
      next[6] = clamp(next[6]||0, 0, 180);
    }
  } else {
    // no arm info — keep whatever rest provided (already assigned)
    next[6] = clamp(next[6]||0, 0, 180);
  }

  const { key, st } = getState(hand);
  const now = Date.now();
  if (now - (st.lastTs||0) < minIntervalMs) { st.live = next.slice(); context.set(key, st); return null; }

  let changed = false;
  for (let i=0;i<8;i++) if (Math.abs((next[i]|0)-(st.lastSent[i]|0)) >= thresholdDeg) { changed=true; break; }
  if (!changed) { st.live = next.slice(); context.set(key, st); return null; }

  const out = { payload: frameA(next), hand };
  st.lastSent = next.slice(); st.live = next.slice(); st.lastTs = now; context.set(key, st);
  return out;
}

// ======== path B: legacy 'virtual' -> angles mapping =======================
let virtual = payload.virtual;
let vobj = {thumb:null,index:null,middle:null,ring:null,pinky:null};
if (Array.isArray(virtual)) { vobj.index=virtual[0]||null; vobj.middle=virtual[1]||null; vobj.ring=virtual[2]||null; vobj.pinky=virtual[3]||null; if (payload.thumb && typeof payload.thumb.flex==='number') vobj.thumb=payload.thumb; }
else if (virtual && typeof virtual==='object') { vobj=Object.assign(vobj,virtual); }
else { return null; }

const Fmax = (typeof msg.Fmax==='number') ? msg.Fmax : (cal.Fmax||60);
function getFlex(e){ if (e==null) return null; if (typeof e==='number') return clamp(e,0,Fmax); if (typeof e.flex==='number') return clamp(Number(e.flex),0,Fmax); return null; }
let iF=getFlex(vobj.index), mF=getFlex(vobj.middle), rF=getFlex(vobj.ring), pF=getFlex(vobj.pinky), tF=getFlex(vobj.thumb);
if (iF===null && mF!==null) iF=mF; if (mF===null && iF!==null) mF=iF; if (rF===null) rF=(mF!==null?mF:iF); if (pF===null) pF=(rF!==null?rF:mF);
if (tF===null && cal.mirrorIndexToThumb && iF!==null) tF=iF;
const openA = Array.isArray(cal.open)?cal.open:[0,0,0,0,0]; const closeA = Array.isArray(cal.close)?cal.close:[160,160,160,160,160];
function flexToAngle(f,idx){ const t = clamp((f||0)/Fmax,0,1); return lerp(openA[idx]||0, closeA[idx]||160, t); }

const next = [];
next[0] = (tF==null) ? (openA[0]||0) : flexToAngle(tF,0);
next[1] = flexToAngle(iF||0,1);
next[2] = flexToAngle(mF||0,2);
next[3] = flexToAngle(rF||0,3);
next[4] = flexToAngle(pF||0,4);
const rest = Array.isArray(payload.rest) ? payload.rest : (Array.isArray(msg.restAngles) ? msg.restAngles : (cal.rest||[90,90,90]));
next[5]=clamp(Math.round(rest[0]||90),0,180); next[6]=clamp(Math.round(rest[1]||90),0,180); next[7]=clamp(Math.round(rest[2]||90),0,180);

// Integrate bicep for legacy virtual path (same logic as above)
if (payload.arm && typeof payload.arm === 'object') {
  let bVal = null;
  if (typeof payload.arm.bicep_servo === 'number') {
    bVal = Math.round(payload.arm.bicep_servo);
  } else if (typeof payload.arm.norm === 'number') {
    const norm = clamp(Number(payload.arm.norm), 0, 1);
    bVal = Math.round(norm * (BICEP_MAX - BICEP_MIN) + BICEP_MIN);
  } else if (typeof payload.arm.elbow_deg === 'number') {
    const deg = Number(payload.arm.elbow_deg);
    const norm = clamp((ELBOW_MAX_DEG - deg) / Math.max(1e-6, (ELBOW_MAX_DEG - ELBOW_MIN_DEG)), 0, 1);
    bVal = Math.round(norm * (BICEP_MAX - BICEP_MIN) + BICEP_MIN);
  }
  if (bVal !== null && !Number.isNaN(bVal)) {
    next[6] = clamp(Math.round(bVal), BICEP_MIN, BICEP_MAX);
  }
}

const { key, st } = getState(hand);
const now = Date.now();
if (now - (st.lastTs||0) < minIntervalMs) { st.live = next.slice(); context.set(key, st); return null; }
let changed=false; for (let i=0;i<8;i++) if (Math.abs((next[i]||0)-(st.lastSent[i]||0)) >= thresholdDeg) { changed=true; break; }
if (!changed) { st.live = next.slice(); context.set(key, st); return null; }
const out = { payload: frameA(next), hand };
st.lastSent = next.slice(); st.live = next.slice(); st.lastTs = now; context.set(key, st);
return out;

// ===== helpers: framed packets with XOR checksum ===========================
function xorChecksum(str){
  let x=0;
  for (let i=0;i<str.length;i++) x ^= str.charCodeAt(i);
  return x.toString(16).toUpperCase().padStart(2,'0');
}
function frameA(a){
  a = (a||[]).slice(0,8).map(v => Math.max(0, Math.min(180, ~~v||0)));
  while (a.length < 8) a.push(0);
  const body = `RA:${a.join(',')}`;
  return `<${body}*${xorChecksum(body)}>\n`;
}
function frameV(s){
  s = (s||[]).slice(0,8).map(v => Math.max(0, Math.min(255, ~~v||0)));
  while (s.length < 8) s.push(0);
  const body = `RV:${s.join(',')}`;
  return `<${body}*${xorChecksum(body)}>\n`;
}

// ===== globals/state =======================================================
let gestures   = global.get('gestures') || {};
let ang        = global.get('angle')    || [90,90,90,90,90,90,90,90];
let lastSpeed  = context.get('lastSpeed') || [0,0,0,0,0,0,0,0];
let plan       = context.get('plan') || null;   // {name, steps, defaultMs, idx, mode, dir, cyclesLeft}
let waiting    = context.get('waiting') || false;

const DEFAULT_STEP_MS   = 200;
const SAFETY_MARGIN_MS  = 150;

// ===== utilities ===========================================================
function arraysEqual(a,b){ if(!a||!b||a.length!==b.length) return false; for(let i=0;i<a.length;i++) if((a[i]|0)!==(b[i]|0)) return false; return true; }
function sanitizeAngles(stepArr, prev){
  const out = prev.slice();
  for (let i=0;i<8;i++){
    const v = stepArr[i];
    if (v===null || v===undefined || v==='') continue;
    out[i] = Math.max(0, Math.min(180, ~~v));
  }
  return out;
}
function mergeSpeeds(base, override){
  const out = base.slice();
  for (let i=0;i<8;i++){
    const v = override[i];
    if (v===null || v===undefined || v==='') continue;
    out[i] = Math.max(0, Math.min(255, ~~v));
  }
  return out;
}
function msPerDeg(s){ if(s===0) return 0; return (300 - ((s-1)*298)/254)|0; }
function estimateStepTime(currentAngles, targetAngles, speed){
  let maxMs = 0;
  for (let i=0;i<8;i++){
    const delta = Math.abs((targetAngles[i]|0) - (currentAngles[i]|0));
    const per   = msPerDeg(speed[i]|0);
    const t     = (speed[i]===0) ? 0 : delta * per;
    if (t > maxMs) maxMs = t;
  }
  return maxMs + SAFETY_MARGIN_MS;
}
function sendIfSpeedChanged(newSpeed){
  if (!newSpeed) return;
  if (!arraysEqual(newSpeed, lastSpeed)){
    node.send({ payload: frameV(newSpeed) });
    lastSpeed = newSpeed.slice();
    context.set('lastSpeed', lastSpeed);
  }
}
function clearPendingTimer(){
  const tid = context.get('pendingTimerId');
  if (tid) { clearTimeout(tid); context.set('pendingTimerId', null); }
}

// Case-insensitive gesture fetch
function getGestureCI(name){
  if (!name) return null;
  if (gestures[name]) return { key: name, val: gestures[name] };
  const lower = String(name).toLowerCase();
  for (const k of Object.keys(gestures)){
    if (k.toLowerCase() === lower) return { key: k, val: gestures[k] };
  }
  return null;
}

// ===== virtual mapping (no raw angles needed) ==============================
// Calibration: can be overridden by global 'sfCal' = {Amin,Amax,Smin,Smax,Fmin,Fmax}
function getCal(){
  const g = global.get('sfCal') || {};
  return {
    Amin: g.Amin ?? 30, Amax: g.Amax ?? 150,
    Smin: g.Smin ?? 50, Smax: g.Smax ?? 140,
    Fmin: g.Fmin ?? 0,  Fmax: g.Fmax ?? 60
  };
}
// Max allowed flex for a given S so A,B stay inside [Amin..Amax]
function Fhi(S, cal){ return Math.max(0, Math.min(cal.Fmax, S - cal.Amin, cal.Amax - S)); }

// Convert a single virtual value {flex, abduct} -> {A,B} with safety clamp
function vfToAB(vf, cal){
  let S = Number(vf?.abduct); if (!Number.isFinite(S)) S = 90;
  let F = Number(vf?.flex);   if (!Number.isFinite(F)) F = 0;

  // clamp S, then clamp F to [0 .. Fhi(S)]
  S = Math.max(cal.Smin, Math.min(cal.Smax, S));
  F = Math.max(cal.Fmin, Math.min(Fhi(S, cal), F));

  // map to motors and final clamp to absolute bounds
  let A = Math.round(S - F);
  let B = Math.round(S + F);
  A = Math.max(cal.Amin, Math.min(cal.Amax, A));
  B = Math.max(cal.Amin, Math.min(cal.Amax, B));
  return {A,B};
}

// Build an 8-angle step from optional "virtual" array (length <= 4).
// Unspecified fingers remain NULL so sanitizeAngles() keeps previous values.
function virtualToAnglesStep(vArr, prevAng){
  const cal = getCal();
  const out = new Array(8).fill(null);
  if (!Array.isArray(vArr)) return out;
  for (let i=0; i<Math.min(4, vArr.length); i++){
    const {A,B} = vfToAB(vArr[i], cal);
    out[i*2]   = A;
    out[i*2+1] = B;
  }
  return out;
}

// ===== repeat helpers ======================================================
function parseRepeat(gestureObj, runOverride){
  const r = (runOverride && runOverride.repeat) || gestureObj.repeat || {};
  const mode = (r.mode === 'pingpong' || r.mode === 'loop') ? r.mode : null;
  let cycles = Number(r.cycles);
  const infinite = !(cycles > 0);
  cycles = infinite ? Infinity : cycles|0;
  return { mode, cyclesLeft: cycles, infinite };
}

function advancePlanIndex(plan){
  // plan: {idx, steps[], mode|null, dir, cyclesLeft}
  const last = plan.steps.length - 1;

  if (!plan.mode){
    plan.idx += 1;
    return;
  }

  if (plan.mode === 'loop'){
    if (plan.idx >= last){
      if (plan.cyclesLeft === Infinity || plan.cyclesLeft > 1){
        if (plan.cyclesLeft !== Infinity) plan.cyclesLeft -= 1;
        plan.idx = 0;
      } else {
        plan.idx = plan.steps.length; // mark finished
      }
    } else {
      plan.idx += 1;
    }
    return;
  }

  if (plan.mode === 'pingpong'){
    if (plan.steps.length <= 1){ plan.idx = plan.steps.length; return; }

    if (typeof plan.dir !== 'number') plan.dir = +1; // forward initially
    plan.idx += plan.dir;

    if (plan.idx > last){
      plan.dir = -1;
      plan.idx = last - 1; // bounce without repeating 'last'
    } else if (plan.idx < 0){
      // completed a full forward+back cycle when we step before 0
      if (plan.cyclesLeft === Infinity || plan.cyclesLeft > 1){
        if (plan.cyclesLeft !== Infinity) plan.cyclesLeft -= 1;
        plan.dir = +1;
        plan.idx = 1; // restart forward without repeating 0
      } else {
        plan.idx = plan.steps.length; // mark finished
      }
    }
  }
}

// ===== core step sender ====================================================
function sendCurrentStep(){
  if (!plan) return;

  // If idx beyond range, we are done
  if (plan.idx >= plan.steps.length){
    node.status({});
    node.warn(`Gesture "${plan.name}" finished (${plan.steps.length} steps).`);
    plan = null; context.set('plan', null);
    waiting = false; context.set('waiting', false);
    return;
  }

  const st = plan.steps[plan.idx];

  // Apply per-step speed if present
  let effectiveSpeed = lastSpeed.slice();
  if (st.speed) {
    effectiveSpeed = mergeSpeeds(effectiveSpeed, st.speed);
    sendIfSpeedChanged(effectiveSpeed);
  }

  // Update angles (allow nulls to keep previous)
  const prevAng = ang.slice();
  ang = sanitizeAngles(st.angles || [], ang);
  global.set('angle', ang);

  // Send A frame for this step
  node.send({ payload: frameA(ang) });

  // Fallback timer (declared vs estimated)
  const declared = Number(st.ms)>0 ? Number(st.ms) : (plan.defaultMs || DEFAULT_STEP_MS);
  const est      = estimateStepTime(prevAng, ang, effectiveSpeed);
  const fallbackMs = Math.max(declared, est);

  clearPendingTimer();
  const tid = setTimeout(() => {
    waiting = false; context.set('waiting', waiting);
    advancePlanIndex(plan);
    context.set('plan', plan);
    node.status({fill:"yellow",shape:"ring",
      text: (plan.idx < plan.steps.length)
        ? `fallback → ${plan.name} step ${plan.idx+1}/${plan.steps.length}`
        : `finished (fallback)`
    });
    sendCurrentStep();
  }, fallbackMs);
  context.set('pendingTimerId', tid);

  waiting = true; context.set('waiting', waiting);
  node.status({fill:"blue",shape:"dot",text:`${plan.name} step ${plan.idx+1}/${plan.steps.length}`});
}

// ===== gesture start =======================================================
function materializeSteps(rawSteps){
  // Turn [{angles?},{virtual?}] into canonical [{angles, ms?, speed?}, ...]
  const steps = [];
  for (const st of (rawSteps||[])){
    const ms    = Number(st?.ms) > 0 ? (st.ms|0) : undefined;
    const speed = Array.isArray(st?.speed) ? st.speed.slice(0,8) : undefined;

    let angles;
    if (Array.isArray(st?.angles)){
      angles = st.angles; // could include nulls; sanitize later
    } else if (Array.isArray(st?.virtual)){
      // Build partial step: unspecified fingers stay null (keep previous)
      angles = virtualToAnglesStep(st.virtual, ang);
    } else {
      // No angles / virtual provided → no-op step (all nulls)
      angles = new Array(8).fill(null);
    }
    steps.push({ angles, ms, speed });
  }
  return steps;
}

function startGesture(name, runOverride){
  gestures = global.get('gestures') || {};  // refresh in case loader updated it
  const found = getGestureCI(name);
  if (!found) {
    const keys = Object.keys(gestures);
    node.status({fill:"red",shape:"ring",text:`gesture "${name}" not found`});
    node.warn(`Gesture "${name}" not found. Available: [${keys.join(', ')}]`);
    return;
  }
  const g = found.val;

  const defaultMs    = Number(g.stepMs)>0 ? Number(g.stepMs) : DEFAULT_STEP_MS;
  const gestureSpeed = Array.isArray(g.speed) ? g.speed.slice(0,8) : null;

  const steps = materializeSteps(g.steps || []);

  if (gestureSpeed) sendIfSpeedChanged(mergeSpeeds(lastSpeed, gestureSpeed));

  clearPendingTimer();

  const rep = parseRepeat(g, runOverride);
  plan = { name: found.key, steps, defaultMs, idx: 0, mode: rep.mode, dir: +1, cyclesLeft: rep.cyclesLeft };
  context.set('plan', plan);

  waiting = false; context.set('waiting', waiting);
  sendCurrentStep();
}

// Start an inline, one-off plan passed directly as a message (no file entry)
function startInlinePlan(def){
  const defaultMs    = Number(def.stepMs)>0 ? (def.stepMs|0) : DEFAULT_STEP_MS;
  const gestureSpeed = Array.isArray(def.speed) ? def.speed.slice(0,8) : null;
  const steps        = materializeSteps(def.steps || def.virtualSteps || []);

  if (gestureSpeed) sendIfSpeedChanged(mergeSpeeds(lastSpeed, gestureSpeed));

  clearPendingTimer();
  plan = { name: def.name || '(inline)', steps, defaultMs, idx: 0,
           mode: (def.repeat && (def.repeat.mode==='loop'||def.repeat.mode==='pingpong')) ? def.repeat.mode : null,
           dir: +1,
           cyclesLeft: (def.repeat && Number(def.repeat.cycles)>0) ? (def.repeat.cycles|0) : Infinity };
  context.set('plan', plan);

  waiting = false; context.set('waiting', waiting);
  sendCurrentStep();
}

// ===== ENTRY ===============================================================
let payload = msg.payload;

// STOP button / cancel current plan
if (payload && typeof payload === 'object' && payload.stop === true){
  clearPendingTimer();
  plan = null; context.set('plan', null);
  waiting = false; context.set('waiting', waiting);
  node.status({fill:"red",shape:"ring",text:"stopped"});
  return null;
}

// Serial feedback path (advance on DONE; ignore info lines)
if (typeof payload === 'string') {
  const s = payload.trim();
  if (s === 'DONE' && waiting && plan) {
    waiting = false; context.set('waiting', waiting);
    clearPendingTimer();
    advancePlanIndex(plan);
    context.set('plan', plan);
    sendCurrentStep();
    return null;
  }
  if (s === 'OK' || s.startsWith('RX:') || s.startsWith('ERR') || s === 'HAND READY' || s.startsWith('POS:') || s.startsWith('LIM:') || s.startsWith('OK ')) {
    return null;
  }
  // otherwise fall through: treat as a possible gesture name string
}
// --- STREAMING: direct virtual payload {virtual:[{flex,abduct}×4]} ---
if (payload && typeof payload === 'object' && Array.isArray(payload.virtual)) {
  // Build partial step: unspecified fingers remain previous values
  const step = virtualToAnglesStep(payload.virtual, ang);   // uses vfToAB + calibration
  ang = sanitizeAngles(step, ang);
  global.set('angle', ang);

  // optional: keep lastSpeed or set a default once, e.g. [200,...]
  // sendIfSpeedChanged(lastSpeed);

  node.send({ payload: frameA(ang) });
  return null; // we're done for this message
}

// Gesture request: string or {gesture:"..."} / {name:"..."} with optional repeat override
let gestureName, runOverride=null;
if (typeof payload === 'object' && payload) {
  if (payload.gesture) gestureName = String(payload.gesture).trim();
  else if (payload.name) gestureName = String(payload.name).trim();
  if (payload.repeat) runOverride = payload;
} else {
  gestureName = String(payload || '').trim();
}

// Trigger by name
if (gestureName) {
  startGesture(gestureName, runOverride);
  return null; // frames are emitted via node.send() above
}

// Inline definition: { stepMs?, speed?, steps:[{angles? or virtual?}] , repeat? }
if (payload && typeof payload === 'object' && (Array.isArray(payload.steps) || Array.isArray(payload.virtualSteps))) {
  startInlinePlan(payload);
  return null;
}

return null;

// === helpers ===
function xorChecksum(str){
  let x = 0;
  for (let i = 0; i < str.length; i++) x ^= str.charCodeAt(i);
  return x.toString(16).toUpperCase().padStart(2,'0');
}
function frame(body){ return `<${body}*${xorChecksum(body)}>\n`; }

// Remember the last positions the Mega reported (used when setting limits)
let lastPos = context.get('lastPos') || new Array(8).fill(90);

// ---- 1) From Serial-In: capture "POS:..." and swallow it ----
if (typeof msg.payload === 'string') {
  const s = msg.payload.trim();

