  if (payload && typeof payload === 'object' && Number.isInteger(payload.motor) && (payload.dir === 1 || payload.dir === -1)) {
    const idx = payload.motor | 0;
    if (idx >= 0 && idx < 8) return { m: idx, d: payload.dir };
  }

  return null;
}

// ---------- ENTRY ----------
const isSpeedJog = (String(msg.topic || '').toUpperCase() === 'SPEED');
const cmd = parseCommand(msg.payload);
if (!cmd) return null;

if (!isSpeedJog) {
  // ANGLE jog
  const stepDeg = Math.max(1, (global.get('stepDeg') | 0) || DEFAULT_STEP);
  const angles = getAngles();
  const { min, max } = getLimits();

  const before = angles[cmd.m];
  let after = clamp(before + cmd.d * stepDeg, min[cmd.m], max[cmd.m]);

  // extra safety: enforce M7 cap regardless of limits
  if (cmd.m === M7_IDX) after = clamp(after, 0, M7_MAX_DEG);

  angles[cmd.m] = after;

  global.set('angle', angles);
  node.status({ fill: 'blue', shape: 'dot', text: `M${cmd.m + 1}: ${before} → ${after}°` });

  msg.payload = { trig: 'jog', motor: cmd.m, val: after, by: stepDeg };
  return msg;

} else {
  // SPEED jog (0..255), ±1 per keypress
  const speeds = getSpeeds();
  const before = speeds[cmd.m];
  let after = clamp(before + cmd.d * SPEED_STEP, 0, 255);
  speeds[cmd.m] = after;

  global.set('speed255', speeds);
  node.status({ fill: 'green', shape: 'dot', text: `V${cmd.m + 1}: ${before} → ${after}` });

  // Let your packet builder notice this and send RV:/LV: from global.speed255,
  // or handle it here if you prefer by emitting a distinct trigger:
  msg.payload = { trig: 'jogSpeed', motor: cmd.m, val: after, by: SPEED_STEP };
  return msg;
}

/***********************
 * Hand Type Packet Compiler (send only changed sides)
 * Inputs:
 *   - Right dropdown: topic = "right.handType", payload = "IM" | "AH" | "NONE"
 *   - Left  dropdown: topic = "left.handType",  payload = "IM" | "AH" | "NONE"
 *   - Button:          topic = "send"
 *   - (optional) Inject once: topic = "forceSend" (still sends only changed sides)
 ***********************/

/*** CONFIG ***/
// If true, a dropdown change sends immediately (in addition to the button).
const SEND_ON_CHANGE = false;
// If true, block sending unless at least one side is IM/AH (skips if both NONE).
const REQUIRE_ANY_SET = true;

/*** Helpers ***/
function hex2(n){ return ('0'+(n & 0xFF).toString(16)).slice(-2).toUpperCase(); }
function xorChecksum(s){ let x=0; for (let i=0;i<s.length;i++) x ^= s.charCodeAt(i); return hex2(x); }
function normVal(v){
  if (v && typeof v === 'object' && v.value != null) v = v.value; // ui_dropdown object
  v = String(v == null ? '' : v).trim().toUpperCase();
  if (v === 'INMOOV') v = 'IM';
  if (v === 'AMAZING' || v === 'AMAZINGHAND') v = 'AH';
  if (v !== 'IM' && v !== 'AH') v = 'NONE';
  return v;
}
function normTopic(t){
  t = String(t||'').trim();
  if (t.startsWith('msg.')) t = t.slice(4).trim(); // tolerate "msg. send"
  return t.replace(/\s+/g,'').toLowerCase();
}

/*** State ***/
// Current selections (what the dropdowns say right now)
let state    = flow.get('hand_meta_state')      || { RH:'NONE', LH:'NONE' };
// Last sent state, tracked per side (we only update the sides we actually transmit)
let lastSent = flow.get('hand_last_sent_state') || { RH:'NONE', LH:'NONE' };

/*** Classify message ***/
const t = normTopic(msg.topic);
let side = null;
if (t === 'right.handtype' || t === 'right' || t === 'r') side = 'RH';
else if (t === 'left.handtype' || t === 'left' || t === 'l') side = 'LH';

let didUpdate = false;

/*** Handle dropdown updates (store only) ***/
if (side === 'RH' || side === 'LH') {
  const v = normVal(msg.payload);
  if (state[side] !== v) { state[side] = v; didUpdate = true; }
  flow.set('hand_meta_state', state);

  if (!SEND_ON_CHANGE) {
    node.status({ fill: (v==='NONE'?'yellow':'grey'), shape:'ring', text: `${side}=${v} (ready)` });
    return null; // waits for button / forceSend
  }
}

/*** Decide whether to attempt sending ***/
const isButton = (t === 'send');
const isForce  = (t === 'forcesend') || (msg.force === true);
const shouldTrySend = isButton || isForce || (SEND_ON_CHANGE && didUpdate);

if (!shouldTrySend) {
  if (t && !side) node.status({fill:'yellow', shape:'ring', text:`ignored topic: ${msg.topic}`});
  return null;
}

/*** Compute which sides changed since the last packet ***/
const rhChanged = (state.RH !== lastSent.RH);
const lhChanged = (state.LH !== lastSent.LH);

// Build tokens ONLY for the sides that changed, and only if set (IM/AH)
const tokens = [];
if (rhChanged && (state.RH === 'IM' || state.RH === 'AH')) tokens.push(`RH:${state.RH}`);
if (lhChanged && (state.LH === 'IM' || state.LH === 'AH')) tokens.push(`LH:${state.LH}`);

// If nothing changed (and not force), skip
if (!isForce && tokens.length === 0) {
  node.status({ fill:'grey', shape:'ring', text:'no change since last send' });
  return null;
}

// (Optional) require at least one side to be set (prevents sending if both NONE)
if (REQUIRE_ANY_SET && state.RH === 'NONE' && state.LH === 'NONE') {
  node.status({ fill:'red', shape:'dot', text:'both sides = NONE' });
  return null;
}

// If forceSend and still no tokens (e.g., both changed to NONE), do not send
if (tokens.length === 0) {
  node.status({ fill:'grey', shape:'ring', text:'nothing to send' });
  return null;
}

/*** Compile the frame ***/
const body  = tokens.join(';') + ';';
const cs    = xorChecksum(body);
const frame = `<${body}*${cs}>`;

/*** Update lastSent ONLY for the sides we actually sent ***/
tokens.forEach(tok => {
  // tok looks like "RH:IM" or "LH:AH"
  const k = tok.slice(0,2);           // "RH" or "LH"
  const v = tok.slice(3);             // "IM"/"AH"
  lastSent[k] = v;
});
flow.set('hand_last_sent_state', lastSent);

/*** Output ***/
node.status({ fill:'green', shape:'dot', text: frame });
msg.payload = frame;
return msg;
